import os
import re
import unicodedata
from flask import Flask, send_from_directory, abort, redirect, url_for, request

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'uploads')
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

# Ensure uploads directory exists
os.makedirs(UPLOAD_FOLDER, exist_ok=True)


def sanitize_filename(filename):
    """Sanitize filename to prevent directory traversal attacks."""
    # Remove any directory components
    filename = os.path.basename(filename)
    # Remove null bytes
    filename = filename.replace('\x00', '')
    return filename


def normalize_legacy_filename(filename):
    """
    Normalize filenames to support older naming conventions.
    
    Legacy conventions supported:
    - Spaces replaced with underscores or hyphens
    - Mixed case filenames (case-insensitive matching)
    - URL-encoded characters (%20 for spaces, etc.)
    - Files with legacy date prefixes (YYYYMMDD_ or YYYY-MM-DD_)
    - Files with numeric prefixes (001_, 002_, etc.)
    - Unicode characters normalized to ASCII equivalents
    - Double extensions (e.g., .tar.gz, .backup.sql)
    - Legacy uppercase extensions (.JPG, .PNG, .PDF)
    """
    # First sanitize
    filename = sanitize_filename(filename)
    
    # Normalize unicode characters to ASCII
    normalized = unicodedata.normalize('NFKD', filename)
    ascii_filename = normalized.encode('ascii', 'ignore').decode('ascii')
    
    # Generate possible legacy name variants
    variants = set()
    variants.add(filename)
    variants.add(ascii_filename)
    
    # Space/underscore/hyphen variants
    base_variants = [filename, ascii_filename]
    for base in base_variants:
        variants.add(base.replace(' ', '_'))
        variants.add(base.replace(' ', '-'))
        variants.add(base.replace('_', ' '))
        variants.add(base.replace('_', '-'))
        variants.add(base.replace('-', '_'))
        variants.add(base.replace('-', ' '))
    
    # Case variants
    case_variants = set()
    for v in variants:
        case_variants.add(v.lower())
        case_variants.add(v.upper())
        # Also handle extension case changes
        name_part, ext = os.path.splitext(v)
        case_variants.add(name_part + ext.lower())
        case_variants.add(name_part + ext.upper())
        case_variants.add(name_part.lower() + ext.lower())
        case_variants.add(name_part.lower() + ext.upper())
    variants.update(case_variants)
    
    # Legacy prefix variants (strip date or numeric prefixes)
    prefix_variants = set()
    for v in list(variants):
        # Strip YYYYMMDD_ prefix
        stripped = re.sub(r'^\d{8}_', '', v)
        prefix_variants.add(stripped)
        # Strip YYYY-MM-DD_ prefix
        stripped = re.sub(r'^\d{4}-\d{2}-\d{2}_', '', v)
        prefix_variants.add(stripped)
        # Strip numeric prefix like 001_
        stripped = re.sub(r'^\d{1,4}_', '', v)
        prefix_variants.add(stripped)
    variants.update(prefix_variants)
    
    # Remove empty strings
    variants.discard('')
    
    return variants


def find_file_in_uploads(filename):
    """
    Find a file in the uploads directory, trying various legacy naming conventions.
    Returns the actual filename on disk if found, None otherwise.
    """
    upload_folder = app.config['UPLOAD_FOLDER']
    
    # Direct match first (most efficient)
    sanitized = sanitize_filename(filename)
    direct_path = os.path.join(upload_folder, sanitized)
    if os.path.isfile(direct_path):
        return sanitized
    
    # Generate all possible variants of the requested filename
    requested_variants = normalize_legacy_filename(filename)
    
    # Get all files in the upload directory
    try:
        existing_files = os.listdir(upload_folder)
    except OSError:
        return None
    
    # Build a lookup map: lowercase -> actual filename
    file_lookup_lower = {}
    for f in existing_files:
        file_path = os.path.join(upload_folder, f)
        if os.path.isfile(file_path):
            file_lookup_lower.setdefault(f.lower(), f)
    
    # Try to match requested variants against existing files
    for variant in requested_variants:
        # Direct variant match
        if variant in existing_files:
            return variant
        # Case-insensitive match
        lower_variant = variant.lower()
        if lower_variant in file_lookup_lower:
            return file_lookup_lower[lower_variant]
    
    # Reverse matching: generate variants for each existing file 
    # and see if any match the requested filename
    for existing_file in existing_files:
        if not os.path.isfile(os.path.join(upload_folder, existing_file)):
            continue
        existing_variants = normalize_legacy_filename(existing_file)
        # Check if any variant of the existing file matches any variant of the request
        existing_lower = {v.lower() for v in existing_variants}
        requested_lower = {v.lower() for v in requested_variants}
        if existing_lower & requested_lower:
            return existing_file
    
    return None


@app.route('/uploads/<path:filename>')
def serve_upload(filename):
    """
    Serve static files from the uploads directory with legacy filename support.
    
    Supports:
    - Direct file serving
    - Legacy filename resolution (spaces, underscores, hyphens)
    - Case-insensitive file matching
    - Legacy date/numeric prefix handling
    - Subdirectory support
    """
    # Security: prevent directory traversal
    # Normalize the path and ensure it doesn't escape uploads
    safe_filename = os.path.normpath(filename)
    if safe_filename.startswith('..') or safe_filename.startswith('/'):
        abort(403)
    
    upload_folder = app.config['UPLOAD_FOLDER']
    
    # Check if there's a subdirectory component
    dirname = os.path.dirname(safe_filename)
    basename = os.path.basename(safe_filename)
    
    if dirname:
        # Handle subdirectories
        sub_upload_folder = os.path.join(upload_folder, dirname)
        # Security check: ensure resolved path is within upload folder
        resolved = os.path.realpath(sub_upload_folder)
        upload_real = os.path.realpath(upload_folder)
        if not resolved.startswith(upload_real):
            abort(403)
        
        if os.path.isdir(sub_upload_folder):
            # Save and temporarily change upload folder context
            original_folder = app.config['UPLOAD_FOLDER']
            app.config['UPLOAD_FOLDER'] = sub_upload_folder
            actual_filename = find_file_in_uploads(basename)
            app.config['UPLOAD_FOLDER'] = original_folder
            
            if actual_filename:
                full_path = os.path.join(sub_upload_folder, actual_filename)
                resolved_full = os.path.realpath(full_path)
                if not resolved_full.startswith(upload_real):
                    abort(403)
                return send_from_directory(sub_upload_folder, actual_filename)
    else:
        # No subdirectory, search in main uploads folder
        actual_filename = find_file_in_uploads(basename)
        if actual_filename:
            # Final security check
            full_path = os.path.realpath(os.path.join(upload_folder, actual_filename))
            upload_real = os.path.realpath(upload_folder)
            if not full_path.startswith(upload_real):
                abort(403)
            return send_from_directory(upload_folder, actual_filename)
    
    # File not found with any naming convention
    abort(404)


@app.route('/uploads/')
def list_uploads():
    """List all files in the uploads directory (for debugging/admin purposes)."""
    upload_folder = app.config['UPLOAD_FOLDER']
    try:
        files = []
        for f in sorted(os.listdir(upload_folder)):
            filepath = os.path.join(upload_folder, f)
            if os.path.isfile(filepath):
                stat = os.stat(filepath)
                files.append({
                    'name': f,
                    'size': stat.st_size,
                    'modified': stat.st_mtime
                })
        
        # Simple HTML listing
        html = '<html><head><title>Uploads Directory</title></head><body>'
        html += '<h1>Uploaded Files</h1>'
        html += '<table border="1" cellpadding="5">'
        html += '<tr><th>Filename</th><th>Size (bytes)</th></tr>'
        for f in files:
            html += f'<tr><td><a href="/uploads/{f["name"]}">{f["name"]}</a></td>'
            html += f'<td>{f["size"]}</td></tr>'
        html += '</table>'
        html += f'<p>Total files: {len(files)}</p>'
        html += '</body></html>'
        return html
    except OSError:
        abort(500)


@app.route('/api/resolve-filename/<path:filename>')
def resolve_filename(filename):
    """
    API endpoint to resolve a legacy filename to its actual filename on disk.
    Useful for migration tools and debugging.
    """
    actual = find_file_in_uploads(os.path.basename(filename))
    if actual:
        return {
            'requested': filename,
            'resolved': actual,
            'url': f'/uploads/{actual}',
            'found': True
        }
    return {
        'requested': filename,
        'resolved': None,
        'found': False
    }, 404


@app.errorhandler(404)
def not_found(error):
    return {'error': 'File not found', 'message': 'The requested file could not be found with any known naming convention.'}, 404


@app.errorhandler(403)
def forbidden(error):
    return {'error': 'Forbidden', 'message': 'Access to the requested resource is forbidden.'}, 403


